class Solution {
public:
    int solve(vector<int>& queue) {
        if (queue.size() == 0) {
            return 0;
        }
        int max = queue[0];
        for (int i = 1; i < queue.size(); i++) {
            if (queue[i] > max) {
                max = queue[i];
            }
        }
        return max;
    }
};
test_cases = [
    {'input': '5 10 20 30 40 50', 'output': '50'}
];
ifstream fin("tests.txt");
ofstream fout("output.txt");
for (auto& test : test_cases) {
    fin >> test['input'];
    fin >> test['output'];
fout << solution.solve(test['input'].split()) << endl;
}
fin.close();
fout.close();
